package be.schaubroeck.lpb.rkm.rekenmotor.util;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.enumtypes.AkeTijdperk;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.exception.MessageException;
import be.schaubroeck.lpb.tools.rsz.RszConstants;
import be.schaubroeck.lpb.tools.service.ConstantService;
import be.schaubroeck.lpb.tools.util.LocalDateUtils;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import be.schaubroeck.temporal.interval.Month;
import com.google.common.collect.Ordering;
import org.joda.time.LocalDate;
import org.joda.time.LocalDateTime;
import org.joda.time.LocalTime;

import java.util.ArrayList;
import java.util.List;
import java.util.function.Predicate;

public class TimeTools {

    private final ConstantManager constantManager;

    public TimeTools(Admin admin, NlpGlobalService nlpGlobalService) {
        this.constantManager = new ConstantManagerImp(admin, nlpGlobalService.getConstantService());
    }

    public TimeTools(Admin admin, ConstantService constantService) {
        this.constantManager = new ConstantManagerImp(admin, constantService);
    }

    public int bepaalFiscaalJaar(RekenTijd rekenTijd) {
        return bepaalFiscaalJaar(rekenTijd.beginDatum, rekenTijd.rekenDatum, rekenTijd.isApo);
    }

    public int bepaalFiscaalJaar(LocalDate begindatum, LocalDate rekenDatum, boolean isApo) {
        int fiscaalJaar = rekenDatum.getYear();
        if (!isApo) {
            //Deze call can falen in APOs in een periode waar deze constante niet gedefinieerd os
            LocalDate datumAfsluitenFiscaalJaar = constantManager.getByCodeDatum(Konstanten.KST_FISKAAL_JAAR, begindatum).getDatum();
            if (rekenDatum.isBefore(datumAfsluitenFiscaalJaar)) {
                fiscaalJaar = begindatum.getYear();
            }
        }
        return fiscaalJaar;
    }

    public int bepaalBoekJaar(RekenTijd rekenTijd) {
        return bepaalBoekJaar(rekenTijd, rekenTijd.boekDatum);
    }

    public int bepaalBoekJaar(RekenTijd rekenTijd, LocalDate boekDatum) {
        int boekJaar;
        LocalDate datumAfsluitenBoekJaar = bepaalAfsluitenBoekJaar(rekenTijd);
        if (!rekenTijd.isApo && !datumAfsluitenBoekJaar.isBefore(boekDatum)) {
            boekJaar = rekenTijd.beginDatum.getYear();
        } else {
            boekJaar = boekDatum.getYear();
        }
        return boekJaar;
    }

    public Predicate<LocalDate> getIsBoekAchterstalTester(RekenTijd rekenTijd) {
        LocalDate datumAfsluitenBoekJaar = bepaalAfsluitenBoekJaar(rekenTijd);
        return boekDatum -> boekDatum.isAfter(datumAfsluitenBoekJaar);
    }

    //Grens om te checken of de opgeslagen datum afsluiten boekjaar echte data betreft.
    private static final int GRENS_JUISTE_DATA_BOEKJAAR = 2000;

    private LocalDate bepaalAfsluitenBoekJaar(RekenTijd rekenTijd) {
        LocalDate datumAfsluitenBoekJaar = constantManager.getByCodeDatum(Konstanten.KST_AFSLUITEN_BOEKJAAR, rekenTijd.beginDatum).getDatum();
        if (datumAfsluitenBoekJaar.getYear() < GRENS_JUISTE_DATA_BOEKJAAR) {
            datumAfsluitenBoekJaar = constantManager.getByCodeDatum(Konstanten.KST_FISKAAL_JAAR, rekenTijd.beginDatum).getDatum().minusDays(1);
        }
        return datumAfsluitenBoekJaar;
    }

    public static LocalDate getNlpEndOfTime() {
        return LocalDateUtils.NLP_END_OF_TIME;
    }

    public static LocalDate getNlpBeginOfTime() {
        return LocalDateUtils.NLP_BEGIN_OF_TIME;
    }

    public static LocalDateTime getMinimumTijdstip() {
        return LocalDateUtils.NLP_BEGIN_OF_TIME.toLocalDateTime(LocalTime.MIDNIGHT);
    }

    public static LocalDate getZoekDatum(Opper opper, LocalDate rekenDatum, LocalDateInterval rekenPeriode) {
        LocalDateInterval opperInterval = opper.getActualInterval();
        LocalDateInterval doorsnede = opperInterval.overlap(rekenPeriode);
        if (doorsnede != null) {
            return doorsnede.getEnd();
        } else {
            return rekenDatum.isBefore(opper.getActualTo()) ? rekenDatum : opper.getActualTo();
        }
    }

    public static LocalDate getZoekDatum(Opper opper, LocalDateInterval rekenPeriode) {
        SleutelGegevens gegevens = new SleutelGegevensSingleOpper(opper);
        return getZoekDatum(gegevens, rekenPeriode);
    }

    public static LocalDate getZoekDatum(SleutelGegevens gegevens, LocalDateInterval rekenPeriode) {
        LocalDateInterval opperInterval = gegevens.getActualInterval();
        LocalDateInterval doorsnede = opperInterval.overlap(rekenPeriode);
        if (doorsnede != null) {
            return doorsnede.getEnd();
        } else {
            return opperInterval.getStart();
        }
    }

    public static void checkRekenTijd(RekenTijd rekenTijd) {
        LocalDate begin = rekenTijd.beginDatum;
        LocalDate einde = rekenTijd.eindDatum;
        if (!(begin.equals(einde.dayOfMonth().withMinimumValue()) && einde.equals(begin.dayOfMonth().withMaximumValue()))) {
            throw new MessageException("RekenTijd fout, de rekenperiode moet altijd exact een maand beslaan");
        }
    }

    public static int bepaalKwartaal(LocalDate datum) {
        return (datum.getMonthOfYear() - 1) / 3 + 1;
    }

    public static LocalDate bepaalSelectieDatumVorigKwartaalDmfappl(RekenTijd rekenTijd) {
        return bepaalSelectieDatumVorigKwartaalDmfappl(rekenTijd.eindDatum);
    }

    public static LocalDate bepaalSelectieDatumVorigKwartaalDmfappl(LocalDate datum) {
        AkeTijdperk tijdperk = RekenTools.getTijdperk(datum);
        LocalDate selectieVorigKwartaal = datum;
        if (tijdperk == AkeTijdperk.DMFAPPL) {
            int kwartaal = bepaalKwartaal(datum);
            int startMaand = (kwartaal * 3) - 2;
            if (datum.getYear() != RszConstants.START_DMFAPPL.getYear() || kwartaal != 1) {
                selectieVorigKwartaal = datum.withMonthOfYear(startMaand).minusMonths(1);
            } else {
                selectieVorigKwartaal = RszConstants.START_DMFAPPL;
            }
            selectieVorigKwartaal = selectieVorigKwartaal.dayOfMonth().withMaximumValue();
        }
        return selectieVorigKwartaal;
    }

    public static List<Month> splitsInMaanden(LocalDateInterval interval) {
        List<Month> maanden = new ArrayList<>();
        LocalDate datum = interval.getStart();
        Month maand = new Month(datum);
        maanden.add(maand);
        while (maand.getEnd().isBefore(interval.getEnd())) {
            maand = new Month(maand.getEnd().plusMonths(1));
            maanden.add(maand);
        }
        return maanden;
    }

    public static List<LocalDateInterval> splitsIntervalOpMaandGrenzen(LocalDateInterval periode) {
        List<LocalDateInterval> lijst = new ArrayList<>();
        LocalDateInterval current = periode;
        boolean done = false;
        while (!done) {
            if (isInSameMonth(current.getStart(), current.getEnd())) {
                lijst.add(current);
                done = true;
            } else {
                LocalDate splitsDatum = current.getStart().dayOfMonth().withMaximumValue();
                lijst.add(new LocalDateInterval(current.getStart(), splitsDatum));
                current = new LocalDateInterval(splitsDatum.plusDays(1), current.getEnd());
            }
        }
        return lijst;
    }

    public static boolean isInSameMonth(LocalDate datum1, LocalDate datum2) {
        return datum1.getMonthOfYear() == datum2.getMonthOfYear() && datum2.getYear() == datum1.getYear();
    }

    public static LocalDateInterval union(LocalDateInterval interval1, LocalDateInterval interval2) {
        LocalDate beginDatum = Ordering.natural().min(interval1.getStart(), interval2.getStart());
        LocalDate eindDatum = Ordering.natural().max(interval1.getEnd(), interval2.getEnd());
        return new LocalDateInterval(beginDatum, eindDatum);
    }

}
